import numpy as np
import itertools
import json

def task_func(data_list, json_file_name="mean_values.json"):
    positions = list(itertools.count())  # Generates positions (0, 1, 2, ...)
    mean_values = {}
    for i, position in enumerate(positions):
        if np.issubdtype(type(data_list[i]), np.number):  # Checks if the element is a number
            mean_values['Position ' + str(position)] = np.mean(data_list[:i+1])

    file_exported = False
    try:
        with open(json_file_name, "w") as f:
            json.dump(mean_values, f)
            file_exported = True
    except Exception as e:
        print(f"Error occurred while exporting to JSON file: {e}")

    return tuple((mean_values, file_exported))
